const alert = $input.first().json;

const SEVERITY_LEVELS = { p1: 4, p2: 3, p3: 2, p4: 1 };
const severity = alert.severity?.toLowerCase() || 'p3';
const level = SEVERITY_LEVELS[severity] || 2;

// Determine channels by severity
const channelMap = {
  slack:  { p1: true, p2: true, p3: true,  p4: false },
  discord: { p1: true, p2: true, p3: true,  p4: false },
  telegram: { p1: true, p2: true, p3: false, p4: false },
  email: { p1: true, p2: true, p3: true,  p4: true },
  sms:   { p1: true, p2: false, p3: false, p4: false },
};

const channels = alert.channels || Object.entries(channelMap)
  .filter(([_, levels]) => levels[severity])
  .map(([ch]) => ch);

// Format Slack Block Kit
const emoji = severity === 'p1' ? '🔴' : severity === 'p2' ? '🟠' : severity === 'p3' ? '🟡' : '🟢';
const slackPayload = {
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `${emoji} [${severity.toUpperCase()}] ${alert.title}` } },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: `*Source:*\n${alert.source || 'unknown'}` },
      { type: 'mrkdwn', text: `*Severity:*\n${severity.toUpperCase()}` },
      { type: 'mrkdwn', text: `*Body:*\n${alert.body}` },
      ...(alert.tags ? [{ type: 'mrkdwn', text: `*Tags:*\n${alert.tags.join(', ')}` }] : [])
    ]},
    ...(alert.runbook_url ? [{ type: 'actions', elements: [{ type: 'button', text: { type: 'plain_text', text: '📖 Runbook' }, url: alert.runbook_url, action_id: 'runbook' }] }] : [])
  ]
};

return [{ json: { ...alert, channels, slackPayload, severity_level: level } }];

const alert = $input.first().json;
const channels = alert.channels || [];

// Only proceed if this channel is requested
return channels.includes('slack') ? $input.all() : [];

const alert = $input.first().json;
const channels = alert.channels || [];
return channels.includes('discord') ? $input.all() : [];

const alert = $input.first().json;
const channels = alert.channels || [];
return channels.includes('telegram') ? $input.all() : [];
